'use client';

import React, { useState } from 'react';

const Footer: React.FC = () => {
  const [hoveredLink, setHoveredLink] = useState<string | null>(null);

  const currentYear = new Date().getFullYear();

  // ─── STYLES ───────────────────────────────────────────────
  const styles: { [key: string]: React.CSSProperties } = {
    footer: {
      width: '100%',
      backgroundColor: '#1f2937',
      color: '#d1d5db',
      fontFamily: "'Poppins', sans-serif",
    },
    container: {
      maxWidth: '1280px',
      margin: '0 auto',
      padding: '48px 24px 0',
    },
    gridRow: {
      display: 'flex',
      flexWrap: 'wrap',
      gap: '40px',
      justifyContent: 'space-between',
    },

    // ── Column ──
    column: {
      flex: '1 1 220px',
      minWidth: '200px',
      marginBottom: '32px',
    },

    // ── Logo / Brand ──
    logoWrapper: {
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'flex-start',
      textDecoration: 'none',
      cursor: 'pointer',
      lineHeight: 1.1,
      marginBottom: '16px',
    },
    logoBilling: {
      fontFamily: "'Poppins', sans-serif",
      fontWeight: 700,
      fontSize: '24px',
      color: '#ED1A3B',
      letterSpacing: '1px',
      textTransform: 'uppercase' as const,
    },
    logoSoftware: {
      fontFamily: "'Poppins', sans-serif",
      fontWeight: 400,
      fontSize: '13px',
      color: '#ED1A3B',
      letterSpacing: '3.5px',
      textTransform: 'uppercase' as const,
    },
    brandDescription: {
      fontSize: '14px',
      color: '#9ca3af',
      lineHeight: 1.7,
      marginTop: '12px',
      maxWidth: '280px',
    },

    // ── Section Heading ──
    columnTitle: {
      fontSize: '16px',
      fontWeight: 600,
      color: '#ffffff',
      marginBottom: '20px',
      textTransform: 'uppercase' as const,
      letterSpacing: '0.5px',
    },

    // ── Links ──
    linkList: {
      listStyle: 'none',
      padding: 0,
      margin: 0,
      display: 'flex',
      flexDirection: 'column',
      gap: '12px',
    },
    link: {
      color: '#9ca3af',
      textDecoration: 'none',
      fontSize: '14px',
      fontFamily: "'Poppins', sans-serif",
      transition: 'color 0.2s',
      cursor: 'pointer',
    },
    linkHover: {
      color: '#ED1A3B',
    },

    // ── Contact Info ──
    contactItem: {
      display: 'flex',
      alignItems: 'flex-start',
      gap: '12px',
      marginBottom: '16px',
    },
    contactIcon: {
      marginTop: '2px',
      flexShrink: 0,
    },
    contactText: {
      fontSize: '14px',
      color: '#9ca3af',
      lineHeight: 1.6,
    },
    contactLabel: {
      fontSize: '12px',
      color: '#6b7280',
      fontWeight: 500,
      textTransform: 'uppercase' as const,
      letterSpacing: '0.5px',
      marginBottom: '2px',
    },
    contactValue: {
      fontSize: '14px',
      color: '#d1d5db',
      textDecoration: 'none',
      fontWeight: 500,
    },

    // ── Social Icons ──
    socialRow: {
      display: 'flex',
      gap: '12px',
      marginTop: '20px',
    },
    socialIcon: {
      width: '36px',
      height: '36px',
      borderRadius: '50%',
      backgroundColor: '#374151',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      cursor: 'pointer',
      transition: 'background-color 0.2s',
      border: 'none',
    },

    // ── Divider ──
    divider: {
      borderTop: '1px solid #374151',
      marginTop: '16px',
    },

    // ── Bottom Bar ──
    bottomBar: {
      display: 'flex',
      flexWrap: 'wrap',
      justifyContent: 'space-between',
      alignItems: 'center',
      padding: '20px 24px',
      maxWidth: '1280px',
      margin: '0 auto',
      gap: '12px',
    },
    copyright: {
      fontSize: '13px',
      color: '#6b7280',
    },
    bottomLinks: {
      display: 'flex',
      gap: '24px',
    },
    bottomLink: {
      fontSize: '13px',
      color: '#6b7280',
      textDecoration: 'none',
      fontFamily: "'Poppins', sans-serif",
      transition: 'color 0.2s',
      cursor: 'pointer',
    },
  };

  // ─── RESPONSIVE CSS ───────────────────────────────────────
  const responsiveCSS = `
    @media (max-width: 768px) {
      .footer-grid {
        flex-direction: column;
        gap: 8px;
      }
      .footer-column {
        min-width: 100% !important;
      }
      .footer-bottom-bar {
        flex-direction: column;
        text-align: center;
      }
      .footer-bottom-links {
        justify-content: center;
      }
    }
  `;

  // ─── NAV LINKS DATA ───────────────────────────────────────
  const quickLinks = ['Dashboard', 'Invoices', 'Customers', 'Reports', 'Settings'];
  const resourceLinks = ['Help Center', 'Documentation', 'API Reference', 'Blog', 'Updates'];

  // ─── HELPER ────────────────────────────────────────────────
  const NavLink = ({ label }: { label: string }) => (
    <li>
      <a
        href="#"
        style={{
          ...styles.link,
          ...(hoveredLink === label ? styles.linkHover : {}),
        }}
        onMouseEnter={() => setHoveredLink(label)}
        onMouseLeave={() => setHoveredLink(null)}
      >
        {label}
      </a>
    </li>
  );

  return (
    <>
      <style>{responsiveCSS}</style>

      <footer style={styles.footer}>
        <div style={styles.container}>
          <div className="footer-grid" style={styles.gridRow}>

            {/* ── Column 1: Brand ── */}
            <div className="footer-column" style={styles.column}>
              <a href="/" style={styles.logoWrapper}>
                <span style={styles.logoBilling}>Billing</span>
                <span style={styles.logoSoftware}>Software</span>
              </a>
              <p style={styles.brandDescription}>
                Simplify your invoicing, manage customers, and track payments
                — all in one powerful billing platform built for modern businesses.
              </p>

              {/* Social Icons */}
              <div style={styles.socialRow}>
                {/* Facebook */}
                <button
                  style={styles.socialIcon}
                  aria-label="Facebook"
                  onMouseEnter={(e) =>
                    (e.currentTarget.style.backgroundColor = '#ED1A3B')
                  }
                  onMouseLeave={(e) =>
                    (e.currentTarget.style.backgroundColor = '#374151')
                  }
                >
                  <svg width="18" height="18" fill="#d1d5db" viewBox="0 0 24 24">
                    <path d="M22 12c0-5.523-4.477-10-10-10S2 6.477 2 12c0 4.991 3.657 9.128 8.438 9.878v-6.987h-2.54V12h2.54V9.797c0-2.506 1.492-3.89 3.777-3.89 1.094 0 2.238.195 2.238.195v2.46h-1.26c-1.243 0-1.63.771-1.63 1.562V12h2.773l-.443 2.89h-2.33v6.988C18.343 21.128 22 16.991 22 12z" />
                  </svg>
                </button>

                {/* Twitter / X */}
                <button
                  style={styles.socialIcon}
                  aria-label="Twitter"
                  onMouseEnter={(e) =>
                    (e.currentTarget.style.backgroundColor = '#ED1A3B')
                  }
                  onMouseLeave={(e) =>
                    (e.currentTarget.style.backgroundColor = '#374151')
                  }
                >
                  <svg width="18" height="18" fill="#d1d5db" viewBox="0 0 24 24">
                    <path d="M18.244 2.25h3.308l-7.227 8.26 8.502 11.24H16.17l-5.214-6.817L4.99 21.75H1.68l7.73-8.835L1.254 2.25H8.08l4.713 6.231zm-1.161 17.52h1.833L7.084 4.126H5.117z" />
                  </svg>
                </button>

                {/* LinkedIn */}
                <button
                  style={styles.socialIcon}
                  aria-label="LinkedIn"
                  onMouseEnter={(e) =>
                    (e.currentTarget.style.backgroundColor = '#ED1A3B')
                  }
                  onMouseLeave={(e) =>
                    (e.currentTarget.style.backgroundColor = '#374151')
                  }
                >
                  <svg width="18" height="18" fill="#d1d5db" viewBox="0 0 24 24">
                    <path d="M20.447 20.452h-3.554v-5.569c0-1.328-.027-3.037-1.852-3.037-1.853 0-2.136 1.445-2.136 2.939v5.667H9.351V9h3.414v1.561h.046c.477-.9 1.637-1.85 3.37-1.85 3.601 0 4.267 2.37 4.267 5.455v6.286zM5.337 7.433a2.062 2.062 0 01-2.063-2.065 2.064 2.064 0 112.063 2.065zm1.782 13.019H3.555V9h3.564v11.452zM22.225 0H1.771C.792 0 0 .774 0 1.729v20.542C0 23.227.792 24 1.771 24h20.451C23.2 24 24 23.227 24 22.271V1.729C24 .774 23.2 0 22.222 0h.003z" />
                  </svg>
                </button>

                {/* Instagram */}
                <button
                  style={styles.socialIcon}
                  aria-label="Instagram"
                  onMouseEnter={(e) =>
                    (e.currentTarget.style.backgroundColor = '#ED1A3B')
                  }
                  onMouseLeave={(e) =>
                    (e.currentTarget.style.backgroundColor = '#374151')
                  }
                >
                  <svg width="18" height="18" fill="#d1d5db" viewBox="0 0 24 24">
                    <path d="M12 2.163c3.204 0 3.584.012 4.85.07 3.252.148 4.771 1.691 4.919 4.919.058 1.265.069 1.645.069 4.849 0 3.205-.012 3.584-.069 4.849-.149 3.225-1.664 4.771-4.919 4.919-1.266.058-1.644.07-4.85.07-3.204 0-3.584-.012-4.849-.07-3.26-.149-4.771-1.699-4.919-4.92-.058-1.265-.07-1.644-.07-4.849 0-3.204.013-3.583.07-4.849.149-3.227 1.664-4.771 4.919-4.919 1.266-.057 1.645-.069 4.849-.069zM12 0C8.741 0 8.333.014 7.053.072 2.695.272.273 2.69.073 7.052.014 8.333 0 8.741 0 12c0 3.259.014 3.668.072 4.948.2 4.358 2.618 6.78 6.98 6.98C8.333 23.986 8.741 24 12 24c3.259 0 3.668-.014 4.948-.072 4.354-.2 6.782-2.618 6.979-6.98.059-1.28.073-1.689.073-4.948 0-3.259-.014-3.667-.072-4.947-.196-4.354-2.617-6.78-6.979-6.98C15.668.014 15.259 0 12 0zm0 5.838a6.162 6.162 0 100 12.324 6.162 6.162 0 000-12.324zM12 16a4 4 0 110-8 4 4 0 010 8zm6.406-11.845a1.44 1.44 0 100 2.881 1.44 1.44 0 000-2.881z" />
                  </svg>
                </button>
              </div>
            </div>

            {/* ── Column 2: Quick Links ── */}
            <div className="footer-column" style={styles.column}>
              <h4 style={styles.columnTitle}>Quick Links</h4>
              <ul style={styles.linkList}>
                {quickLinks.map((link) => (
                  <NavLink key={link} label={link} />
                ))}
              </ul>
            </div>

            {/* ── Column 3: Resources ── */}
            <div className="footer-column" style={styles.column}>
              <h4 style={styles.columnTitle}>Resources</h4>
              <ul style={styles.linkList}>
                {resourceLinks.map((link) => (
                  <NavLink key={link} label={link} />
                ))}
              </ul>
            </div>

            {/* ── Column 4: Customer Care ── */}
            <div className="footer-column" style={styles.column}>
              <h4 style={styles.columnTitle}>Customer Care</h4>

              {/* Phone */}
              <div style={styles.contactItem}>
                <div style={styles.contactIcon}>
                  <svg
                    width="20"
                    height="20"
                    fill="none"
                    stroke="#ED1A3B"
                    strokeWidth="2"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    viewBox="0 0 24 24"
                  >
                    <path d="M22 16.92v3a2 2 0 01-2.18 2 19.79 19.79 0 01-8.63-3.07 19.5 19.5 0 01-6-6 19.79 19.79 0 01-3.07-8.67A2 2 0 014.11 2h3a2 2 0 012 1.72 12.84 12.84 0 00.7 2.81 2 2 0 01-.45 2.11L8.09 9.91a16 16 0 006 6l1.27-1.27a2 2 0 012.11-.45 12.84 12.84 0 002.81.7A2 2 0 0122 16.92z" />
                  </svg>
                </div>
                <div>
                  <div style={styles.contactLabel}>Phone</div>
                  <a href="tel:+918001234567" style={{ ...styles.contactValue, textDecoration: 'none' }}>
                    +91 800-123-4567
                  </a>
                  <br />
                  <a href="tel:+911800001234" style={{ ...styles.contactValue, textDecoration: 'none', fontSize: '13px', color: '#9ca3af' }}>
                    Toll-Free: 1800-001-234
                  </a>
                </div>
              </div>

              {/* Email */}
              <div style={styles.contactItem}>
                <div style={styles.contactIcon}>
                  <svg
                    width="20"
                    height="20"
                    fill="none"
                    stroke="#ED1A3B"
                    strokeWidth="2"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    viewBox="0 0 24 24"
                  >
                    <rect x="2" y="4" width="20" height="16" rx="2" />
                    <path d="M22 4l-10 7L2 4" />
                  </svg>
                </div>
                <div>
                  <div style={styles.contactLabel}>Email</div>
                  <a href="mailto:support@billingsoftware.com" style={{ ...styles.contactValue, textDecoration: 'none' }}>
                    support@billingsoftware.com
                  </a>
                  <br />
                  <a href="mailto:sales@billingsoftware.com" style={{ ...styles.contactValue, textDecoration: 'none', fontSize: '13px', color: '#9ca3af' }}>
                    sales@billingsoftware.com
                  </a>
                </div>
              </div>

              {/* Working Hours */}
              <div style={styles.contactItem}>
                <div style={styles.contactIcon}>
                  <svg
                    width="20"
                    height="20"
                    fill="none"
                    stroke="#ED1A3B"
                    strokeWidth="2"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    viewBox="0 0 24 24"
                  >
                    <circle cx="12" cy="12" r="10" />
                    <polyline points="12 6 12 12 16 14" />
                  </svg>
                </div>
                <div>
                  <div style={styles.contactLabel}>Working Hours</div>
                  <div style={styles.contactValue}>Mon – Sat: 9 AM – 7 PM</div>
                  <div style={{ ...styles.contactValue, fontSize: '13px', color: '#9ca3af' }}>
                    Sunday: Closed
                  </div>
                </div>
              </div>

              {/* Address */}
              <div style={styles.contactItem}>
                <div style={styles.contactIcon}>
                  <svg
                    width="20"
                    height="20"
                    fill="none"
                    stroke="#ED1A3B"
                    strokeWidth="2"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    viewBox="0 0 24 24"
                  >
                    <path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z" />
                    <circle cx="12" cy="10" r="3" />
                  </svg>
                </div>
                <div>
                  <div style={styles.contactLabel}>Office</div>
                  <div style={styles.contactValue}>
                    123 Business Park, Tower B,
                    <br />
                    Bengaluru, Karnataka 560001
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* ── Bottom Bar ── */}
        <div style={styles.divider} />
        <div className="footer-bottom-bar" style={styles.bottomBar}>
          <p style={styles.copyright}>
            © {currentYear} <span style={{ color: '#ED1A3B', fontWeight: 600 }}>Billing Software</span>. All rights reserved.
          </p>
          <div className="footer-bottom-links" style={styles.bottomLinks}>
            {['Privacy Policy', 'Terms of Service', 'Cookie Policy'].map((link) => (
              <a
                key={link}
                href="#"
                style={{
                  ...styles.bottomLink,
                  ...(hoveredLink === `bottom-${link}` ? { color: '#ED1A3B' } : {}),
                }}
                onMouseEnter={() => setHoveredLink(`bottom-${link}`)}
                onMouseLeave={() => setHoveredLink(null)}
              >
                {link}
              </a>
            ))}
          </div>
        </div>
      </footer>
    </>
  );
};

export default Footer;